-- Data Sisipan Baru (Menggunakan SELECT & CROSS JOIN):
INSERT IGNORE INTO `smartjabar_usage_stats` (service_type_id, opd_id, month, year, total_asn, active_users, created_at, updated_at)
SELECT
    2 AS service_type_id,
    o.opd_id,
    m.month,
    2026 AS year,
    o.total_asn,
    CASE m.month
        WHEN 1 THEN FLOOR(o.total_asn * 0.60)
        WHEN 2 THEN FLOOR(o.total_asn * 0.62)
        WHEN 3 THEN FLOOR(o.total_asn * 0.64)
        WHEN 4 THEN FLOOR(o.total_asn * 0.66)
        WHEN 5 THEN FLOOR(o.total_asn * 0.68)
        WHEN 6 THEN FLOOR(o.total_asn * 0.70)
        WHEN 7 THEN FLOOR(o.total_asn * 0.72)
        WHEN 8 THEN FLOOR(o.total_asn * 0.74)
        WHEN 9 THEN FLOOR(o.total_asn * 0.76)
        WHEN 10 THEN FLOOR(o.total_asn * 0.78)
        WHEN 11 THEN FLOOR(o.total_asn * 0.80)
        WHEN 12 THEN FLOOR(o.total_asn * 0.82)
    END AS active_users,
    NOW(),
    NOW()
FROM (
    SELECT 1 AS opd_id, 450 AS total_asn UNION ALL SELECT 2, 520 UNION ALL SELECT 3, 480 UNION ALL SELECT 4, 650 UNION ALL SELECT 5, 550 UNION ALL SELECT 6, 700 UNION ALL SELECT 7, 620 UNION ALL SELECT 8, 530 UNION ALL SELECT 9, 580 UNION ALL SELECT 10, 490 UNION ALL SELECT 11, 760 UNION ALL SELECT 12, 680 UNION ALL SELECT 13, 540 UNION ALL SELECT 14, 610 UNION ALL SELECT 15, 570 UNION ALL SELECT 16, 800 UNION ALL SELECT 17, 470 UNION ALL SELECT 18, 640 UNION ALL SELECT 19, 520 UNION ALL SELECT 20, 720 UNION ALL SELECT 21, 600 UNION ALL SELECT 22, 510 UNION ALL SELECT 23, 670 UNION ALL SELECT 24, 560 UNION ALL SELECT 25, 740 UNION ALL SELECT 26, 630 UNION ALL SELECT 27, 500 UNION ALL SELECT 28, 690 UNION ALL SELECT 29, 580 UNION ALL SELECT 30, 770 UNION ALL SELECT 31, 620 UNION ALL SELECT 32, 540 UNION ALL SELECT 33, 710 UNION ALL SELECT 34, 590 UNION ALL SELECT 35, 660 UNION ALL SELECT 36, 550 UNION ALL SELECT 37, 730 UNION ALL SELECT 38, 610
) o
CROSS JOIN (
    SELECT 1 AS month UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4 UNION ALL SELECT 5 UNION ALL SELECT 6 UNION ALL SELECT 7 UNION ALL SELECT 8 UNION ALL SELECT 9 UNION ALL SELECT 10 UNION ALL SELECT 11 UNION ALL SELECT 12
) m;

